import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Konto-Migration: Backup/Hot-Migration | Antigravity Manager","description":"Lernen Sie Backup und Migration in Antigravity Manager. Unterstützt JSON-Import/-Export, Hot-Migration von Antigravity/IDE, Migration aus V1-Datenverzeichnis und automatische Synchronisation des aktuellen Kontos.","frontmatter":{"title":"Konto-Migration: Backup/Hot-Migration | Antigravity Manager","sidebarTitle":"3 Minuten zur Konto-Migration","subtitle":"Konto-Migration: Backup/Hot-Migration","description":"Lernen Sie Backup und Migration in Antigravity Manager. Unterstützt JSON-Import/-Export, Hot-Migration von Antigravity/IDE, Migration aus V1-Datenverzeichnis und automatische Synchronisation des aktuellen Kontos.","tags":["Kontoverwaltung","Backup","Migration","Import/Export","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"de/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"de/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function o(s,e,d,l,u,h){return i(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="konto-backup-und-migration-import-export-v1-db-hot-migration" tabindex="-1">Konto-Backup und -Migration: Import/Export, V1/DB Hot-Migration <a class="header-anchor" href="#konto-backup-und-migration-import-export-v1-db-hot-migration" aria-label="Permalink to &quot;Konto-Backup und -Migration: Import/Export, V1/DB Hot-Migration&quot;">​</a></h1><p>Was Sie wirklich &quot;sichern&quot; wollen, ist nicht die Quota-Zahl, sondern das <code>refresh_token</code>, mit dem sich das Konto erneut anmelden lässt. In dieser Lektion erklären wir die verschiedenen Migrationsmethoden von Antigravity Tools: JSON-Import/-Export, Import aus <code>state.vscdb</code>, Import aus V1-Datenverzeichnis und wie die automatische Synchronisation funktioniert.</p><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li>Ihr Konto-Pool als JSON-Datei exportieren (nur email + refresh_token)</li><li>Auf einem neuen Computer diese JSON importieren und den Konto-Pool schnell wiederherstellen</li><li>Direkt aus Antigravity/IDE <code>state.vscdb</code> das &quot;aktuell angemeldete Konto&quot; importieren (unterstützt Standardpfad und benutzerdefinierten Pfad)</li><li>Automatisch aus dem V1-Datenverzeichnis alte Konten scannen und importieren</li><li>Verstehen, was &quot;automatische Synchronisation des aktuellen Kontos&quot; tut und wann sie übersprungen wird</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><ul><li>Nach Neuinstallation/Systemwechsel müssen Sie den Konto-Pool neu hinzufügen – das ist teuer</li><li>Sie haben in Antigravity/IDE das angemeldete Konto gewechselt, aber im Manager ist das &quot;aktuelle Konto&quot; nicht mitgegangen</li><li>Sie haben früher V1/Skript-Version verwendet und haben nur alte Datendateien – fragen sich, ob diese direkt migriert werden können</li></ul><h2 id="wann-verwenden-sie-diese-methode" tabindex="-1">Wann verwenden Sie diese Methode <a class="header-anchor" href="#wann-verwenden-sie-diese-methode" aria-label="Permalink to &quot;Wann verwenden Sie diese Methode&quot;">​</a></h2><ul><li>Sie möchten den Konto-Pool auf einen anderen Computer übertragen (Desktop/Server/Container)</li><li>Sie verwenden Antigravity als &quot;autorisches Login-Portal&quot; und möchten, dass der Manager automatisch das aktuelle Konto synchronisiert</li><li>Sie möchten Konten von einer alten Version (V1-Datenverzeichnis) migrieren</li></ul><h2 id="🎒-vorbereitung" tabindex="-1">🎒 Vorbereitung <a class="header-anchor" href="#🎒-vorbereitung" aria-label="Permalink to &quot;🎒 Vorbereitung&quot;">​</a></h2><ul><li>Sie können Antigravity Tools öffnen und haben mindestens ein Konto im Konto-Pool</li><li>Sie wissen, dass Kontodaten sensible Informationen sind (insbesondere <code>refresh_token</code>)</li></ul><div class="warning custom-block"><p class="custom-block-title">Sicherheitswarnung: Behandeln Sie Backup-Dateien wie Passwörter</p><p>Die exportierte JSON-Datei enthält <code>refresh_token</code>. Jeder, der sie hat, könnte sie verwenden, um Access Tokens zu aktualisieren. Laden Sie die Backup-Datei nicht in öffentliche Cloud-Links hoch, senden Sie sie nicht in Gruppen und committen Sie sie nicht nach Git.</p></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>&quot;Migration&quot; in Antigravity Tools läuft im Grunde auf zwei Dinge hinaus:</p><ol><li>Ein verfügbares <code>refresh_token</code> finden</li><li>Damit ein Access Token eintauschen, bei Google die echte E-Mail abrufen und das Konto in den lokalen Konto-Pool schreiben</li></ol><p>Es bietet drei Wege:</p><ul><li>JSON-Import/-Export: Geeignet für &quot;kontrolliertes Backup&quot;</li><li>DB-Import: Geeignet, wenn Sie den Anmeldestatus von Antigravity/IDE als Quelle betrachten (standardmäßig <code>state.vscdb</code>, unterstützt auch manuelle Dateiauswahl)</li><li>V1-Import: Geeignet für automatisches Scannen und Migrieren aus alten Datenverzeichnissen</li></ul><p>Zusätzlich gibt es eine &quot;automatische Synchronisation&quot;: Sie liest periodisch das refresh_token aus der DB. Wenn es vom aktuellen Konto des Managers abweicht, wird automatisch ein DB-Import ausgeführt; wenn es identisch ist, wird es übersprungen (spart Traffic).</p><h2 id="lernen-sie-mit-mir" tabindex="-1">Lernen Sie mit mir <a class="header-anchor" href="#lernen-sie-mit-mir" aria-label="Permalink to &quot;Lernen Sie mit mir&quot;">​</a></h2><h3 id="schritt-1-konto-pool-exportieren-json-backup" tabindex="-1">Schritt 1: Konto-Pool exportieren (JSON-Backup) <a class="header-anchor" href="#schritt-1-konto-pool-exportieren-json-backup" aria-label="Permalink to &quot;Schritt 1: Konto-Pool exportieren (JSON-Backup)&quot;">​</a></h3><p><strong>Warum</strong> Dies ist die stabilste und kontrollierteste Migrationsmethode. Sie erhalten eine Datei, mit der Sie den Konto-Pool auf einem anderen Computer wiederherstellen können.</p><p>Vorgehensweise: Öffnen Sie die Seite <code>Accounts</code>, klicken Sie auf Export.</p><ul><li>Wenn Sie in den Einstellungen <code>default_export_path</code> konfiguriert haben, wird direkt in dieses Verzeichnis exportiert mit dem Dateinamen <code>antigravity_accounts_YYYY-MM-DD.json</code>.</li><li>Wenn kein Standardverzeichnis konfiguriert ist, wird ein System-Dialog angezeigt, in dem Sie den Pfad auswählen können.</li></ul><p>Der Inhalt der exportierten Datei sieht ungefähr so aus (jedes Element im Array enthält nur die notwendigen Felder):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die Seite zeigt &quot;Export erfolgreich&quot; und den Speicherpfad.</p><h3 id="schritt-2-auf-einem-neuen-computer-json-importieren-konto-pool-wiederherstellen" tabindex="-1">Schritt 2: Auf einem neuen Computer JSON importieren (Konto-Pool wiederherstellen) <a class="header-anchor" href="#schritt-2-auf-einem-neuen-computer-json-importieren-konto-pool-wiederherstellen" aria-label="Permalink to &quot;Schritt 2: Auf einem neuen Computer JSON importieren (Konto-Pool wiederherstellen)&quot;">​</a></h3><p><strong>Warum</strong> Der Import führt die &quot;Konto hinzufügen&quot;-Logik für jedes Konto aus, verwendet <code>refresh_token</code>, um die echte E-Mail abzurufen und schreibt sie in den Konto-Pool.</p><p>Vorgehensweise: Öffnen Sie die Seite <code>Accounts</code>, klicken Sie auf &quot;JSON importieren&quot; und wählen Sie die soeben exportierte Datei aus.</p><p>Formatanforderungen (mindestens ein gültiger Eintrag erforderlich):</p><ul><li>Muss ein JSON-Array sein</li><li>Das System importiert nur Einträge, die <code>refresh_token</code> enthalten und mit <code>1//</code> beginnen</li></ul><p><strong>Sie sollten sehen</strong>: Nach dem Import erscheinen die importierten Konten in der Kontoliste.</p><div class="tip custom-block"><p class="custom-block-title">Wenn Sie während des Imports Proxy ausführen</p><p>Nach erfolgreichem &quot;Konto hinzufügen&quot; versucht das Backend, den Token-Pool des Reverse-Proxys neu zu laden, damit das neue Konto sofort wirksam wird.</p></div><h3 id="schritt-3-aktuell-angemeldetes-konto-aus-state-vscdb-importieren" tabindex="-1">Schritt 3: &quot;Aktuell angemeldetes Konto&quot; aus <code>state.vscdb</code> importieren <a class="header-anchor" href="#schritt-3-aktuell-angemeldetes-konto-aus-state-vscdb-importieren" aria-label="Permalink to &quot;Schritt 3: &quot;Aktuell angemeldetes Konto&quot; aus \`state.vscdb\` importieren&quot;">​</a></h3><p><strong>Warum</strong> Manchmal möchten Sie keine Backup-Datei verwalten, sondern einfach &quot;der Anmeldestatus von Antigravity/IDE gilt&quot;. DB-Import ist genau dafür gedacht.</p><p>Vorgehensweise: Öffnen Sie die Seite <code>Accounts</code>, klicken Sie auf <strong>Add Account</strong>, wechseln Sie zur Registerkarte <code>Import</code>:</p><ul><li>Klicken Sie auf &quot;Aus Datenbank importieren&quot; (verwendet den Standard-DB-Pfad)</li><li>Oder klicken Sie auf &quot;Benutzerdefinierte DB (state.vscdb)&quot;, um eine <code>*.vscdb</code>-Datei manuell auszuwählen</li></ul><p>Der Standard-DB-Pfad ist plattformübergreifend (und erkennt auch <code>--user-data-dir</code> oder Portable Mode vorrangig):</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-Fx9Bt" id="tab-QJnTyZ2" checked><label data-title="macOS" for="tab-QJnTyZ2">macOS</label><input type="radio" name="group-Fx9Bt" id="tab-udreYdy"><label data-title="Windows" for="tab-udreYdy">Windows</label><input type="radio" name="group-Fx9Bt" id="tab-w-BxSiG"><label data-title="Linux" for="tab-w-BxSiG">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage\\state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>Sie sollten sehen</strong>:</p><ul><li>Nach erfolgreichem Import wird dieses Konto automatisch als &quot;aktuelles Konto&quot; des Managers festgelegt</li><li>Das System löst automatisch eine Quota-Aktualisierung aus</li></ul><h3 id="schritt-4-aus-v1-datenverzeichnis-migrieren-alte-version-importieren" tabindex="-1">Schritt 4: Aus V1-Datenverzeichnis migrieren (alte Version importieren) <a class="header-anchor" href="#schritt-4-aus-v1-datenverzeichnis-migrieren-alte-version-importieren" aria-label="Permalink to &quot;Schritt 4: Aus V1-Datenverzeichnis migrieren (alte Version importieren)&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie früher die V1/Skript-Version verwendet haben, erlaubt Ihnen Manager, das alte Datenverzeichnis direkt zu scannen und zu versuchen, zu importieren.</p><p>Vorgehensweise: Auf der Registerkarte <code>Import</code> klicken Sie auf &quot;V1 importieren&quot;.</p><p>Es sucht in Ihrem Home-Verzeichnis nach diesem Pfad (und den darin enthaltenen Indexdateien):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Nach Abschluss des Imports erscheinen die Konten in der Liste. Wenn keine Indexdateien gefunden werden, gibt das Backend den Fehler <code>V1 account data file not found</code> zurück.</p><h3 id="schritt-5-optional-automatische-synchronisation-des-aktuellen-kontos-aktivieren" tabindex="-1">Schritt 5 (optional): &quot;Automatische Synchronisation des aktuellen Kontos&quot; aktivieren <a class="header-anchor" href="#schritt-5-optional-automatische-synchronisation-des-aktuellen-kontos-aktivieren" aria-label="Permalink to &quot;Schritt 5 (optional): &quot;Automatische Synchronisation des aktuellen Kontos&quot; aktivieren&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie in Antigravity/IDE das angemeldete Konto wechseln, kann der Manager in festen Intervallen prüfen, ob sich das refresh_token in der DB geändert hat, und bei Änderungen automatisch importieren.</p><p>Vorgehensweise: Öffnen Sie <code>Settings</code>, aktivieren Sie <code>auto_sync</code> und stellen Sie <code>sync_interval</code> ein (Einheit: Sekunden).</p><p><strong>Sie sollten sehen</strong>: Nach der Aktivierung wird sofort einmal synchronisiert. Danach wird periodisch nach dem Intervall ausgeführt. Wenn das refresh_token in der DB mit dem aktuellen Konto übereinstimmt, wird es übersprungen, nicht wiederholt importiert.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>Sie können die importierten Konten in der <code>Accounts</code>-Liste sehen</li><li>Sie sehen, dass das &quot;aktuelle Konto&quot; auf das gewünschte Konto gewechselt wurde (DB-Import setzt es automatisch als aktuell)</li><li>Wenn Sie Proxy starten, können die neu importierten Konten normal für Anforderungen verwendet werden (basierend auf tatsächlichen Aufrufergebnissen)</li></ul><h2 id="fallstricke" tabindex="-1">Fallstricke <a class="header-anchor" href="#fallstricke" aria-label="Permalink to &quot;Fallstricke&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Was Sie vielleicht tun (❌)</th><th>Empfohlene Vorgehensweise (✓)</th></tr></thead><tbody><tr><td>Sicherheit von Backup-Dateien</td><td>Die exportierte JSON wie eine normale Konfigurationsdatei einfach herumschicken</td><td>JSON wie Passwort behandeln, Verbreitung minimieren, öffentliche Exposition vermeiden</td></tr><tr><td>JSON-Import schlägt fehl</td><td>JSON ist kein Array oder refresh_token hat kein <code>1//</code>-Präfix</td><td>Verwenden Sie die von diesem Projekt exportierte JSON als Vorlage, behalten Sie Feldnamen und Struktur bei</td></tr><tr><td>DB-Import findet keine Daten</td><td>Antigravity war noch nie angemeldet oder in der DB fehlt <code>jetskiStateSync.agentManagerInitState</code></td><td>Stellen Sie sicher, dass Antigravity/IDE angemeldet ist, versuchen Sie erneut zu importieren; verwenden Sie bei Bedarf Custom DB, um die richtige Datei auszuwählen</td></tr><tr><td>Konto nach V1-Import nicht verfügbar</td><td>Altes refresh_token ist abgelaufen</td><td>Löschen Sie das Konto und fügen Sie es erneut mit OAuth/neuem refresh_token hinzu (basierend auf Fehlermeldung)</td></tr><tr><td>auto_sync zu häufig</td><td><code>sync_interval</code> sehr klein eingestellt, häufiges Scannen der DB</td><td>Betrachten Sie es als &quot;Status-Folge&quot;, stellen Sie das Intervall auf eine für Sie akzeptable Frequenz</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li>JSON-Export/-Import ist die kontrollierteste Migrationsmethode: Die Backup-Datei enthält nur <code>email + refresh_token</code></li><li>DB-Import eignet sich für &quot;nach aktuell angemeldetem Konto von Antigravity/IDE&quot; und setzt es automatisch als aktuelles Konto des Managers</li><li>V1-Import scannt <code>~/.antigravity-agent</code> und ist mit mehreren alten Formaten kompatibel</li><li>auto_sync vergleicht refresh_token; wenn identisch, wird übersprungen, nicht wiederholt importiert</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion setzen wir den &quot;migrierten Konto-Pool&quot; tatsächlich ein: <strong><a href="./../proxy-and-first-client/">Lokalen Reverse-Proxy starten und ersten Client anschließen (/healthz + SDK-Konfiguration)</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie man Proxy startet/stopt und mit <code>/healthz</code> eine minimale Verifizierung durchführt</li><li>Wie man Base URL in SDK/Clients konfiguriert</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken zum Erweitern, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>`,61)])])}const g=t(r,[["render",o]]);export{p as __pageData,g as default};
